define("block_recommend_course/form-cohort-selector",["core/ajax"],(function(Ajax){return{transport:function(selector,query,success,failure){Ajax.call([{methodname:"block_recommend_course_cohort_search",args:{query:query}}])[0].then((function(results){success(results)})).catch(failure)},processResults:function(selector,results){return results}}}));
